import os, re

projects = {
    'lingclaude': '/home/ai/lingclaude',
    'lingflow': '/home/ai/lingflow',
    'lingflow_plus': '/home/ai/lingflow_plus',
    'lingmessage': '/home/ai/lingmessage',
    'lingyang': '/home/ai/lingyang',
    'lingweb': '/home/ai/lingweb',
    'lingcreate': '/home/ai/lingcreate',
    'lingzhi': '/home/ai/lingzhi',
    'lingtongask': '/home/ai/lingtongask',
    'zhibridge': '/home/ai/zhibridge',
    'linglaw': '/home/ai/linglaw',
}

skip_dirs = {'.git','node_modules','__pycache__','htmlcov','dist','venv','.egg-info','experiments','data','knowledge','null'}

patterns = {
    'silent_except': re.compile(r'except\s*(\w*)\s*:\s*(pass|\.\.\.)\s*#', re.IGNORECASE),
    'bare_except': re.compile(r'except\s*:\s*$'),
    'hardcoded_secret': re.compile(r'(password|secret|api_key|token)\s*=\s*[\"\'][^\"\']{8,}', re.IGNORECASE),
    'print_debug': re.compile(r'print\s*\(\s*f?[\"\'].*debug', re.IGNORECASE),
}

results = {p: {k: [] for k in patterns} for p in projects}
counts = {p: 0 for p in projects}

for name, root in projects.items():
    if not os.path.isdir(root):
        continue
    for dirpath, dirs, files in os.walk(root):
        dirs[:] = [d for d in dirs if d not in skip_dirs]
        for f in files:
            if not f.endswith('.py'):
                continue
            fp = os.path.join(dirpath, f)
            rel = os.path.relpath(fp, root)
            counts[name] += 1
            try:
                content = open(fp, 'r', errors='ignore').read()
                for pname, pat in patterns.items():
                    for m in pat.finditer(content):
                        line_no = content[:m.start()].count('\n') + 1
                        results[name][pname].append(f'{rel}:{line_no}')
            except:
                pass

# Summary
print(f\"{'Project':<16} {'Files':<6} {'bare_except':<12} {'hardcoded':<12} {'print_debug':<12}\")
print('-' * 60)
for name in projects:
    if counts[name] == 0:
        continue
    r = results[name]
    print(f\"{name:<16} {counts[name]:<6} {len(r['bare_except']):<12} {len(r['hardcoded_secret']):<12} {len(r['print_debug']):<12}\")
" 2>/dev/null

