import os, re

projects = {
    'lingclaude': '/home/ai/lingclaude',
    'lingflow': '/home/ai/lingflow',
    'lingzhi': '/home/ai/lingzhi',
    'lingtongask': '/home/ai/lingtongask',
}

skip_dirs = {'.git','node_modules','__pycache__','htmlcov','dist','venv','.egg-info','experiments','data','knowledge','null','tests'}
pat = re.compile(r'(password|secret|api_key|token|api_secret)\s*=\s*[\"\']([^\"\']{8,})', re.IGNORECASE)

for name, root in projects.items():
    hits = []
    for dirpath, dirs, files in os.walk(root):
        dirs[:] = [d for d in dirs if d not in skip_dirs]
        for f in files:
            if not f.endswith('.py'):
                continue
            fp = os.path.join(dirpath, f)
            rel = os.path.relpath(fp, root)
            try:
                for i, line in enumerate(open(fp, 'r', errors='ignore'), 1):
                    m = pat.search(line)
                    if m:
                        key = m.group(1)
                        val = m.group(2)[:30]
                        line_stripped = line.strip()[:120]
                        hits.append(f'  {rel}:{i} {key}=\"{val}...\"  # {line_stripped}')
            except:
                pass
    if hits:
        print(f'=== {name} ({len(hits)} hits) ===')
        for h in hits[:10]:
            print(h)
        if len(hits) > 10:
            print(f'  ... and {len(hits)-10} more')
        print()
" 2>/dev/null

